import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet, ScrollView, TouchableOpacity, ActivityIndicator, Alert } from 'react-native';
import { useTheme } from '../../context/ThemeContext';
import Badge from '../../components/Badge';
import Button from '../../components/Button';
import apiClient from '../../api/client';
import { spacing, fontSize, fontWeight, radius, shadow } from '../../theme';

interface Mess {
  id: string; name: string; address: string;
  opening_time: string; closing_time: string;
  price_range: string | null; is_open: boolean; distance_km?: number;
  latitude: number; longitude: number;
}

function InfoRow({ icon, label, value, color }: { icon: string; label: string; value: string; color: string }) {
  return (
    <View style={infoStyles.row}>
      <Text style={infoStyles.icon}>{icon}</Text>
      <View>
        <Text style={[infoStyles.label, { color }]}>{label}</Text>
        <Text style={[infoStyles.value, { color }]}>{value}</Text>
      </View>
    </View>
  );
}

const infoStyles = StyleSheet.create({
  row: { flexDirection: 'row', alignItems: 'flex-start', marginBottom: spacing.md, gap: 12 },
  icon: { fontSize: 22, marginTop: 2 },
  label: { fontSize: fontSize.xs, opacity: 0.6, marginBottom: 2 },
  value: { fontSize: fontSize.md, fontWeight: fontWeight.medium },
});

export default function MessDetailScreen({ route, navigation }: any) {
  const { messId } = route.params;
  const { colors } = useTheme();
  const [mess, setMess] = useState<Mess | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    apiClient.get(`/messes/${messId}`)
      .then(({ data }) => setMess(data))
      .catch(() => Alert.alert('Error', 'Could not load mess details'))
      .finally(() => setLoading(false));
  }, [messId]);

  if (loading) return (
    <View style={[styles.center, { backgroundColor: colors.background }]}>
      <ActivityIndicator size="large" color={colors.primary} />
    </View>
  );

  if (!mess) return (
    <View style={[styles.center, { backgroundColor: colors.background }]}>
      <Text style={[styles.notFound, { color: colors.textSecondary }]}>Mess not found</Text>
    </View>
  );

  const today = new Date().toISOString().split('T')[0];

  return (
    <ScrollView style={[styles.container, { backgroundColor: colors.background }]} showsVerticalScrollIndicator={false}>
      {/* Hero */}
      <View style={[styles.hero, { backgroundColor: colors.primary }]}>
        <Text style={styles.heroEmoji}>🍽️</Text>
        <Text style={styles.heroName}>{mess.name}</Text>
        <Badge label={mess.is_open ? '● Open Now' : '● Closed'} type={mess.is_open ? 'success' : 'error'} />
        {mess.distance_km !== undefined && (
          <Text style={styles.heroDistance}>{mess.distance_km.toFixed(2)} km away</Text>
        )}
      </View>

      {/* Info card */}
      <View style={[styles.infoCard, { backgroundColor: colors.surface }, shadow.md]}>
        <InfoRow icon="📍" label="Address" value={mess.address} color={colors.text} />
        <InfoRow icon="🕐" label="Hours" value={`${mess.opening_time} – ${mess.closing_time}`} color={colors.text} />
        {mess.price_range && <InfoRow icon="💰" label="Price Range" value={mess.price_range} color={colors.text} />}
      </View>

      {/* CTA */}
      <View style={styles.cta}>
        <Button
          label="📋 View Today's Menu"
          onPress={() => navigation.navigate('Menu', { messId: mess.id, date: today, messName: mess.name })}
        />
      </View>
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1 },
  center: { flex: 1, alignItems: 'center', justifyContent: 'center' },
  notFound: { fontSize: fontSize.lg },
  hero: { padding: spacing.xl, alignItems: 'center', paddingTop: spacing.xxl },
  heroEmoji: { fontSize: 56, marginBottom: spacing.sm },
  heroName: { fontSize: fontSize.xxl, fontWeight: fontWeight.bold, color: '#fff', textAlign: 'center', marginBottom: spacing.sm },
  heroDistance: { color: 'rgba(255,255,255,0.8)', fontSize: fontSize.sm, marginTop: spacing.sm },
  infoCard: { margin: spacing.md, borderRadius: radius.xl, padding: spacing.lg },
  cta: { padding: spacing.md, paddingTop: 0 },
});
